/* RETRO-HUNT EQL: intel--7451f493ec173808c4bd26c0 | Techniques: T1190, T1059, T1190.001 | Lookback: 90d */
sequence with maxspan=90d
  [network where
    destination.ip in ("<ip>")
    or dns.question.name in ("cstecgi.cgi")
  ] by host.id
  [process where
    process.hash.sha256 in ("<hash>")
    or process.hash.md5 in ("<hash>")
  ] by host.id

retro_hunt.chronicle_udm:
/* RETRO-HUNT CHRONICLE UDM: intel--7451f493ec173808c4bd26c0 | Techniques: T1190, T1059, T1190.001 | Lookback: 90d */
/* Google SecOps (Chronicle) UDM Search */
metadata.event_timestamp.seconds > unix_seconds(timestamp_sub(current_timestamp(), interval 90 day))
AND (
    (target.ip = "<ip>")
    OR (network.dns.questions.name = "cstecgi.cgi")
    OR (target.file.sha256 = "<hash>")
)
/* Aggregate by principal hostname */
| group_by principal.hostname
| order_by count() desc

